func:
// Tjek for API fejl eller tom data
if (msg.payload.statusCode) {
    node.warn(`⚠️ API fejl: ${msg.payload.message}`);
    return null;
}

const records = Array.isArray(msg.payload) ? msg.payload : msg.payload.records;

if (!records || records.length === 0) {
    node.warn('⚠️ Tom data modtaget - sandsynligvis i morgens priser ikke klar endnu');
    return null;
}

// Ryd gammel cache hvis den ikke har spotpris felt
const eksisterendeCheck = global.get('priser_raw') || [];
if (eksisterendeCheck.length > 0 && !eksisterendeCheck[0].spotpris) {
    global.set('priser_raw', []);
    node.warn('🔄 Rydder gammel priscache - opdaterer med afgifter');
}

// Afgifter baseret på tidspunkt (Radius C zone)
const getFastTillæg = (hour) => {
    if (hour >= 0 && hour < 6)   return 0.287;
    if (hour >= 6 && hour < 17)  return 0.353;
    if (hour >= 17 && hour < 21) return 0.672;
    return 0.353;
};

// Konverter til DKK/kWh inkl. afgifter
const nyePriser = records.map(r => {
    const hour = new Date(r.time_start).getHours();
    const spotpris = parseFloat(r.DKK_per_kWh.toFixed(4));
    const realPris = parseFloat((spotpris + getFastTillæg(hour)).toFixed(4));
    return {
        time: r.time_start,
        pris: realPris,
        spotpris: spotpris,
        hour: hour
    };
});

// Merge med eksisterende priser (behold begge dage)
const eksisterende = global.get('priser_raw') || [];

// Fjern dubletter baseret på time
const merged = [...eksisterende];
nyePriser.forEach(ny => {
    const findes = merged.find(e => e.time === ny.time);
    if (!findes) merged.push(ny);
});

// Sorter efter tid
merged.sort((a, b) => new Date(a.time).getTime() - new Date(b.time).getTime());

// Gem rådata til næste merge
global.set('priser_raw', merged);

node.warn(`📦 Rådata: ${merged.length} timer total`);

// Dynamiske zoner baseret på alle kendte priser
const sorteret = [...merged].sort((a, b) => a.pris - b.pris);
const antalTimer = sorteret.length;
const billigGraense = sorteret[Math.floor(antalTimer / 3)].pris;
const dyrGraense = sorteret[Math.floor(antalTimer * 2 / 3)].pris;

const markeretPriser = merged.map(p => ({
    ...p,
    zone: p.pris <= billigGraense ? 'billig' : p.pris >= dyrGraense ? 'dyr' : 'normal'
}));

// Find nuværende time
const nu = new Date();
const nuvaerende = markeretPriser.find(p => {
    const t = new Date(p.time);
    return t.getHours() === nu.getHours() &&
           t.getDate() === nu.getDate() &&
           t.getMonth() === nu.getMonth();
});

if (!nuvaerende) {
    node.warn(`⚠️ Ingen pris for nuværende time`);
}

// Tjek om vi har nattetimer
const harNatTimer = markeretPriser.some(p => {
    const t = new Date(p.time);
    return t > nu && t.getDate() !== nu.getDate() && t.getHours() < 6;
});

// Gem globalt
global.set('priser', markeretPriser);
global.set('billigGraense', billigGraense);
global.set('dyrGraense', dyrGraense);
global.set('nuvaerende', nuvaerende);
global.set('har_nok_prisdata', harNatTimer);

node.warn(`✅ Priser: ${markeretPriser.length} timer | Nat: ${harNatTimer ? '✅' : '⏳ venter'}`);
node.warn(`💚 Billig < ${billigGraense} kr/kWh`);
node.warn(`❤️ Dyr > ${dyrGraense} kr/kWh`);
if (nuvaerende) {
    node.warn(`⚡ Nu: ${nuvaerende.pris} kr/kWh (spot: ${nuvaerende.spotpris}) - ${nuvaerende.zone.toUpperCase()}`);
}

msg.payload = { priser: markeretPriser, billigGraense, dyrGraense, nuvaerende, harNatTimer };
return msg;

const nu = new Date();
const år = nu.getFullYear();
const måned = String(nu.getMonth() + 1).padStart(2, '0');
const dag = String(nu.getDate()).padStart(2, '0');

const imorgen = new Date(nu);
imorgen.setDate(imorgen.getDate() + 1);
const imorgeMåned = String(imorgen.getMonth() + 1).padStart(2, '0');
const imorgenDag = String(imorgen.getDate()).padStart(2, '0');

node.warn(`Henter priser for: ${dag}/${måned} og ${imorgenDag}/${imorgeMåned}`);

// Send to beskeder - én for hver dag
const msg2 = { ...msg };
msg.url = `https://www.elprisenligenu.dk/api/v1/prices/${år}/${måned}-${dag}_DK1.json`;
msg.dag = 'idag';
msg2.url = `https://www.elprisenligenu.dk/api/v1/prices/${år}/${imorgeMåned}-${imorgenDag}_DK1.json`;
msg2.dag = 'imorgen';

return [msg, msg2];

const nu = new Date();
const eksisterendePriser = global.get('priser') || [];

// Find gyldige fremtidige ladetimer (16:00 i dag → 06:00 i morgen)
const gyldigeLadeTimer = eksisterendePriser.filter(p => {
    const t = new Date(p.time);
    if (t <= nu) return false;
    const erAftenIdag = t.getDate() === nu.getDate() && t.getHours() >= 16;
    const erNatImorgen = t.getDate() !== nu.getDate() && t.getHours() < 6;
    return erAftenIdag || erNatImorgen;
});

// Har vi nattetimer (00:00-06:00 i morgen)?
const harNatTimer = gyldigeLadeTimer.some(p => {
    const t = new Date(p.time);
    return t.getDate() !== nu.getDate() && t.getHours() < 6;
});

// Har vi aftentimer (16:00-23:59 i dag)?
const harAftenTimer = gyldigeLadeTimer.some(p => {
    const t = new Date(p.time);
    return t.getDate() === nu.getDate() && t.getHours() >= 16;
});

node.warn(`📊 Ladetimer: ${gyldigeLadeTimer.length} | Aften: ${harAftenTimer ? '✅' : '❌'} | Nat: ${harNatTimer ? '✅' : '❌'}`);

// Vi har komplet data hvis vi har BÅDE aften og nattetimer
if (gyldigeLadeTimer.length >= 14 && harAftenTimer && harNatTimer) {
    node.warn('✅ Prisdata komplet - ingen API kald nødvendigt');
    global.set('har_nok_prisdata', true);
    return null; // Stop her!
}

node.warn('⚠️ Mangler prisdata - henter fra API');
global.set('har_nok_prisdata', false);
return msg; // Fortsæt til API hentning

const nu = new Date();
const time = nu.getHours();
const min = nu.getMinutes();
const soc = global.get('batteri_soc') || 0;

// Beregn næste begivenhed
let naeste = [];

// Næste discharge skift
if (time >= 6 && time < 16) {
    const diff = 16 - time;
    naeste.push({ 
        tid: '16:00', 
        besked: '🔋 Dyre timer starter - discharge 100%', 
        minutter: diff * 60 - min 
    });
} else if (time >= 16 && time < 22) {
    const diff = 22 - time;
    naeste.push({ 
        tid: '22:00', 
        besked: '🌙 Nat - discharge 100% fortsætter til 06:00', 
        minutter: diff * 60 - min 
    });
} else {
    // Nat 22-06
    const minutterTil06 = time >= 22 
        ? (24 - time + 6) * 60 - min 
        : (6 - time) * 60 - min;
    naeste.push({ 
        tid: '06:00', 
        besked: '☀️ Dag mode - discharge 0% (sol lader batteri)', 
        minutter: minutterTil06
    });
}

// Batteri advarsel
if (soc <= 15) {
    naeste.unshift({ 
        tid: 'NU', 
        besked: `⚠️ Batteri lavt (${soc}%) - stopper afladning ved 10%`, 
        minutter: 0 
    });
}

// Tesla ladning
const priser = global.get('priser') || [];
const carSoc = global.get('car_soc') || 50;
const goECar = global.get('go_e_car') || 1;

if (goECar > 1) {
    const kommende = priser.filter(p => {
        const t = new Date(p.time);
        const h = t.getHours();
        const erSenAften = t.getDate() === nu.getDate() && h >= 21;
        const erNat = t.getDate() !== nu.getDate() && h < 6;
        return (erSenAften || erNat) && t > nu;
    }).sort((a, b) => a.pris - b.pris);

    if (kommende.length > 0) {
        const kwhMangler = Math.max(0, (100 - carSoc) * 0.60);
        const timerNodvendige = Math.ceil(kwhMangler / 11);
        const billigste = kommende.slice(0, timerNodvendige)
            .sort((a, b) => new Date(a.time).getTime() - new Date(b.time).getTime());
        if (billigste.length > 0) {
            const startTid = new Date(billigste[0].time);
            const fmt = (d) => d.toLocaleTimeString('da-DK', { hour: '2-digit', minute: '2-digit' });
            naeste.push({ 
                tid: fmt(startTid), 
                besked: `🚗 Tesla starter ladning (${carSoc}% → 100%)`, 
                minutter: Math.round((startTid.getTime() - nu.getTime()) / 60000) 
            });
        }
    }
}

// Sidst udført
const sidst = [
    { 
        tid: nu.toLocaleTimeString('da-DK', { hour: '2-digit', minute: '2-digit' }), 
        besked: `⚡ Discharge: ${global.get('discharge_rate') || 0}% | Mode: ${global.get('growatt_kommando') || 'Load first'} | Batteri: ${soc}%` 
    },
];

msg.payload = { naeste, sidst };
return msg;

const list = msg.payload.list || [];
const dagensTimer = list.slice(0, 4);

const maxTemp = Math.max(...dagensTimer.map(t => t.main.temp_max));
const minTemp = Math.min(...dagensTimer.map(t => t.main.temp_min));
const vejrTekst = dagensTimer[0]?.weather[0]?.description || 'ukendt';
const skyer = Math.round(dagensTimer.reduce((sum, t) => sum + t.clouds.all, 0) / dagensTimer.length);
const solPotentiale = skyer < 30 ? '☀️ Højt solpotentiale' : skyer < 70 ? '⛅ Moderat solpotentiale' : '☁️ Lavt solpotentiale';

global.set('vejr_temp_max', Math.round(maxTemp));
global.set('vejr_temp_min', Math.round(minTemp));
global.set('vejr_tekst', vejrTekst);
global.set('vejr_skyer', skyer);
global.set('vejr_sol_potentiale', solPotentiale);

node.warn(`🌤️ Vejr Lunderskov: ${vejrTekst}, ${Math.round(minTemp)}-${Math.round(maxTemp)}°C, ${skyer}% skyer`);
return null;

const val = parseFloat(msg.payload);
global.set('batteri_soc', val);
msg.payload = val;
return msg;

const val = parseFloat(msg.payload);
global.set('batteri_power', val);
msg.payload = val;
return msg;

const val = parseFloat(msg.payload);
global.set('sol_power', val);
msg.payload = val;
return msg;

const val = parseFloat(msg.payload);
global.set('grid_power', val);
msg.payload = val;
return msg;

const val = parseFloat(msg.payload);
global.set('batteri_temp', val);
msg.payload = val;
return msg;

// Tjek override FØRST - kører indtil manuelt stop
const overrideAktiv = global.get('override_aktiv') || false;

if (overrideAktiv) {
    const soc = global.get('batteri_soc') || 0;
    const sol = global.get('sol_power') || 0;
    const grid = global.get('grid_power') || 0;
    node.warn(`🚨 OVERRIDE AKTIV! Tvinger Tesla ladning til 16A`);
    msg.payload = {
        growattMode: 'load_first',
        teslaLad: true,
        teslaAmp: 16,
        soc, sol, grid,
        pris: 0,
        zone: 'override',
        beslutning: ['🚨 MANUEL OVERRIDE AKTIV']
    };
    return msg;
}

// Hent aktuelle værdier
const soc = global.get('batteri_soc') || 0;
const sol = global.get('sol_power') || 0;
const grid = global.get('grid_power') || 0;
const batteriPower = global.get('batteri_power') || 0;
const temp = global.get('batteri_temp') || 0;
const nuvaerende = global.get('nuvaerende');
const priser = global.get('priser') || [];
const loadPower = global.get('load_power') || 0;

if (!nuvaerende) {
    node.warn('⚠️ Ingen prisdata endnu - afventer');
    return null;
}

// Batteri grænser
const GROWATT_MIN_SOC = 10;
const GROWATT_AFLAD_MIN = 50;
const TESLA_MAL = 100;
const TESLA_KWH = 60;
const TESLA_MAX_KW = 11;
const SOL_GRAENSE = 200;
const TESLA_MIN_OVERSKUD = 1200;
const DEADLINE_TIME = 6; // Bilen skal være klar kl. 06:00 hver dag

const pris = nuvaerende.pris;
const zone = nuvaerende.zone;
const nu = new Date();
const time = nu.getHours();
const erDyrAften = time >= 16 && time < 21;
const erSol = sol > SOL_GRAENSE;

// Sol overskud efter husforbrug
const solEfterHus = sol - loadPower;
const erSolOverskud = solEfterHus > TESLA_MIN_OVERSKUD;

// Bilens behov
const carSoc = global.get('car_soc') || 50;
const goECar = global.get('go_e_car') || 1;
const bilTilsluttet = goECar > 1;
const manglerKwh = Math.max(0, (TESLA_MAL - carSoc) * (TESLA_KWH / 100));
const timerNodvendige = Math.ceil(manglerKwh / TESLA_MAX_KW);

// Beregn deadline-tidspunkt (næste forekomst af DEADLINE_TIME)
const deadline = new Date(nu);
deadline.setHours(DEADLINE_TIME, 0, 0, 0);
if (deadline <= nu) {
    deadline.setDate(deadline.getDate() + 1);
}

// Find alle kommende prispunkter FREM TIL deadline
const kommendeTilDeadline = priser.filter(p => {
    const t = new Date(p.time);
    return t > nu && t <= deadline;
});

// Vælg de N billigste timer ud af dem, hvor N = timerNodvendige (mindst 1 hvis bilen mangler noget)
const billigsteTimer = [...kommendeTilDeadline]
    .sort((a, b) => a.pris - b.pris)
    .slice(0, Math.max(timerNodvendige, 1))
    .map(p => new Date(p.time).getHours());

const erBilligTeslaTime = billigsteTimer.includes(time);

// Tving Tesla hvis vi er inde i den udvalgte ladeperiode og tæt på deadline
// (sikkerhedsnet hvis prislogikken af en grund ikke rammer rigtigt)
const timerTilDeadline = (deadline.getTime() - nu.getTime()) / (1000 * 60 * 60);
const maxKwhResterende = timerTilDeadline * TESLA_MAX_KW;
let tvingTesla = false;
if (bilTilsluttet && maxKwhResterende < manglerKwh && manglerKwh > 0) {
    tvingTesla = true;
    node.warn(`⚠️ Tesla kan ikke nå ${TESLA_MAL}% før ${DEADLINE_TIME}:00! Mangler ${manglerKwh.toFixed(1)} kWh, kun ${maxKwhResterende.toFixed(1)} kWh tid tilbage`);
}

// BESLUTNINGER
let growattMode = 'load_first'; // DEFAULT altid load first
let dischargeMode = 'normal';   // normal = kun aflade hvis dyr tid
let teslaLad = false;
let teslaAmp = 0;
let beslutning = [];

// REGEL 1: Dyre aftentimer → Load first + afladning tilladt
if (erDyrAften) {
    growattMode = 'load_first';
    dischargeMode = 'aktiv';
    beslutning.push(`❤️ DYR AFTENTID (${pris} kr) → Load first | Batteri + sol dækker huset`);
    teslaLad = false;
}

// REGEL 2: Sol til stede → Load first
else if (erSol) {
    growattMode = 'load_first';
    dischargeMode = 'stop';
    beslutning.push(`☀️ Sol (${sol}W) → Load first | Hus: ${loadPower}W | Overskud: ${solEfterHus}W`);
}

// REGEL 3: Billig time → Load first + lad Tesla mod deadline, uanset Growatt SOC
else if (zone === 'billig') {
    growattMode = 'load_first';
    dischargeMode = 'stop';
    beslutning.push(`💚 BILLIG TIME (${pris} kr) → Load first`);

    if (bilTilsluttet && carSoc < 100 && erBilligTeslaTime) {
        teslaLad = true;
        teslaAmp = 16;
        beslutning.push(`🚗 Tesla lader mod deadline ${DEADLINE_TIME}:00 (${pris} kr/kWh, ${carSoc}% → 100%, mangler ${manglerKwh.toFixed(1)} kWh)`);
    } else if (bilTilsluttet && carSoc >= 100) {
        beslutning.push(`🚗 Tesla allerede fuldt opladet (${carSoc}%)`);
    } else if (!bilTilsluttet) {
        beslutning.push(`🚗 Tesla ikke tilsluttet - springer billig nat-ladning over`);
    }
}

// REGEL 4: Normal time → Load first
else {
    growattMode = 'load_first';
    dischargeMode = 'stop';
    beslutning.push(`🟡 NORMAL TIME (${pris} kr) → Load first`);
}

// REGEL 5: Sol overskud → lad Tesla (kun hvis Growatt 100%)
if (erSolOverskud && soc >= 100) {
    const teslaAmpBeregnet = Math.floor(solEfterHus / 230);
    if (teslaAmpBeregnet >= 6) {
        teslaLad = true;
        teslaAmp = Math.min(16, teslaAmpBeregnet);
        beslutning.push(`☀️ Growatt 100% + Sol overskud ${solEfterHus}W → Tesla ${teslaAmp}A`);
    } else {
        beslutning.push(`☀️ Sol overskud ${solEfterHus}W → For lidt til Tesla (min 6A = 1380W)`);
    }
} else if (erSol && soc < 100) {
    beslutning.push(`🔋 Growatt ${soc}% → Sol lader batteri først, Tesla venter`);
}

// REGEL 6: Tving Tesla hvis deadline er i fare - tæller over ALLE dage, ikke kun hverdage
if (tvingTesla) {
    teslaLad = true;
    teslaAmp = 16;
    beslutning.push(`🚨 DEADLINE ${DEADLINE_TIME}:00! Tesla tvinges til 16A`);
}

// REGEL 7: Batteri for varm → advar
if (temp > 45) {
    beslutning.push(`🌡️ Growatt batteri for varm (${temp}°C)!`);
}

// Gem beslutning globalt
global.set('growatt_mode', growattMode);
global.set('discharge_mode', dischargeMode);
global.set('tesla_lad', teslaLad);
global.set('tesla_amp', teslaAmp);

node.warn(`📊 Growatt: ${soc}% | Sol: ${sol}W | Hus: ${loadPower}W | Overskud: ${solEfterHus}W | Net: ${grid}W | Pris: ${pris} kr (${zone}) | Bil: ${carSoc}% (mangler ${manglerKwh.toFixed(1)} kWh, behov ${timerNodvendige}h) | ${erDyrAften ? '🔴 DYR AFTEN' : erSol ? '☀️ SOL' : '🌙 NAT'}`);
beslutning.forEach(b => node.warn(b));

msg.payload = { growattMode, teslaLad, teslaAmp, soc, sol, grid, pris, zone, beslutning };
return msg;

const teslaLad = msg.payload.teslaLad;
const teslaAmp = msg.payload.teslaAmp;

if (teslaLad) {
    msg.url = `http://192.168.1.222/api/set?frc=2&amp=${teslaAmp}`;
    node.warn(`🚗 go-e: Lader ${teslaAmp}A`);
} else {
    msg.url = `http://192.168.1.222/api/set?frc=1`;
    node.warn(`🚗 go-e: STOP ladning`);
}

return msg;

const GROWATT_MIN_SOC = 10;
const growattMode = msg.payload.growattMode;
const soc = msg.payload.soc;
const time = new Date().getHours();

// ALTID Load first
const workMode = 'Load first';

// Discharge logik
let dischargeRate = 0;
let dischargeAarsag = '';

if (soc <= GROWATT_MIN_SOC) {
    dischargeRate = 0;
    dischargeAarsag = `Batteri for lavt (${soc}%)`;
    node.warn(`🔋 Batteri for lavt (${soc}%) → Ingen afladning`);
} else if (time >= 6 && time < 16) {
    dischargeRate = 0;
    dischargeAarsag = `Dag mode (${time}:00)`;
    node.warn(`☀️ Dag (06-16) → Spar batteri, sol lader`);
} else {
    dischargeRate = 100;
    dischargeAarsag = `Aften/nat mode (${time}:00)`;
    node.warn(`🔋 Aften/nat (16-06) → Afladning 100%`);
}

global.set('growatt_kommando', workMode);
global.set('discharge_rate', dischargeRate);

node.warn(`⚡ Growatt: ${workMode} | Discharge: ${dischargeRate}%`);

// Log event hvis discharge ændret sig
const sidsteDischarge = global.get('sidste_discharge_rate');
let eventMsg = null;

if (sidsteDischarge !== dischargeRate) {
    global.set('sidste_discharge_rate', dischargeRate);
    eventMsg = {
        payload: {
            event: 'discharge_skift',
            beskrivelse: `Discharge ${sidsteDischarge !== undefined ? sidsteDischarge : '?'}% → ${dischargeRate}% (${dischargeAarsag})`
        }
    };
    node.warn(`📝 Event: Discharge skift ${sidsteDischarge}% → ${dischargeRate}%`);
}

msg.payload = workMode;
msg.topic = 'solar_assistant/inverter_1/work_mode_priority/set';

msg.discharge = {
    payload: dischargeRate.toString(),
    topic: 'solar_assistant/inverter_1/free_mode_discharge_rate/set'
};

return [msg, eventMsg];

msg.payload = msg.discharge.payload;
msg.topic = msg.discharge.topic;
return msg;

const aktiv = msg.payload.aktiv;
let eventMsg = null;

if (aktiv) {
    global.set('override_aktiv', true);
    global.set('override_slut', null);
    node.warn(`🚨 OVERRIDE AKTIV - kører indtil manuelt stop!`);
    msg.payload = { success: true, besked: 'Override aktiv indtil manuelt stop' };
    eventMsg = { payload: { event: 'override', beskrivelse: '🚨 Manuel override aktiveret - Tesla tvinges til 16A' } };
} else {
    global.set('override_aktiv', false);
    global.set('override_slut', null);
    node.warn('✅ Override deaktiveret');
    msg.payload = { success: true, besked: 'Override deaktiveret' };
    eventMsg = { payload: { event: 'override', beskrivelse: '✅ Manuel override deaktiveret' } };
}

return [msg, eventMsg];

const aktiv = global.get('override_aktiv') || false;

msg.payload = { 
    aktiv, 
    minutterTilbage: aktiv ? 999 : 0 
};
return msg;

const car = msg.payload.car || 0;
const amp = msg.payload.amp || 0;
const wh = msg.payload.wh || 0;

global.set('go_e_car', car);
global.set('go_e_amp', amp);
global.set('go_e_wh', wh);

node.warn(`🔌 go-e: car=${car} | amp=${amp}A | wh=${wh}`);
return null;

const event = msg.payload.event;
const beskrivelse = msg.payload.beskrivelse;

if (!event) return null;

const lineProtocol = `events,type=${event.replace(/ /g,'_')} beskrivelse="${beskrivelse}"`;

msg.payload = lineProtocol;
msg.headers = {
    'Authorization': 'Token ' + env.get('INFLUX_TOKEN'),
    'Content-Type': 'text/plain'
};
msg.url = 'http://192.168.1.253:8086/api/v2/write?org=energihub&bucket=energi2&precision=s';
return msg;

msg.payload = null;
msg.headers = {
    'Authorization': 'Token ' + env.get('INFLUX_TOKEN'),
    'Content-Type': 'application/vnd.flux',
    'Accept': 'application/csv'
};
msg.url = 'http://192.168.1.253:8086/api/v2/query?org=energihub';
msg.method = 'POST';
msg.payload = `from(bucket: "energi2") |> range(start: -30d) |> filter(fn: (r) => r._measurement == "events") |> sort(columns: ["_time"], desc: true) |> limit(n: 50)`;
return msg;

